function solve(nums, edges) {
    const n = nums.length;

    // Build adjacency matrix/list for O(1) edge check in the induced subgraph
    const adj = Array(n).fill(0).map(() => Array(n).fill(false));
    for (const [u, v] of edges) {
        adj[u][v] = adj[v][u] = true;
    }

    let count = 0;

    // Iterate through all non-empty subsets s. A subset can be represented by a bitmask from 1 to 2^n - 1.
    const totalSubsets = 1 << n;

    for (let mask = 1; mask < totalSubsets; mask++) {

        // 1. Check the parity of the sum of values in s
        let sum = 0;
        let subsetNodes = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
                subsetNodes.push(i);
            }
        }

        // If sum is odd, this subset fails the second condition
        if (sum % 2 !== 0) {
            continue;
        }

        // 2. Check if the induced subgraph is connected
        const sSize = subsetNodes.length;

        // A single node subset is always connected
        if (sSize === 1) {
            count++;
            continue;
        }

        // Use BFS/DFS starting from the first node in the subset to check connectivity
        const startNode = subsetNodes[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 1;

        while (queue.length > 0) {
            const u = queue.shift();

            // Check neighbors of u
            for (let v = 0; v < n; v++) {
                // Check if v is in the subset AND (u, v) is an edge AND v has not been visited
                if (((mask >> v) & 1) && adj[u][v] && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                    visitedCount++;
                }
            }
        }

        // If the number of visited nodes equals the size of the subset, it is connected.
        if (visitedCount === sSize) {
            count++;
        }
    }

    return count;
}

